/**
 * @summary Cancel a token
 */
export const getCancelTokenUrl = (tokenId: string) => {
  return `/api/tokens/${tokenId}/cancel`;
};

export const cancelToken = async (
  tokenId: string,
  options?: RequestInit,
): Promise<CancelToken200> => {
  return customFetch<CancelToken200>(getCancelTokenUrl(tokenId), {
    ...options,
    method: "PATCH",
  });
};

export const getCancelTokenMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof cancelToken>>,
    TError,
    { tokenId: string },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof cancelToken>>,
  TError,
  { tokenId: string },
  TContext
> => {
  const mutationKey = ["cancelToken"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof cancelToken>>,
    { tokenId: string }
  > = (props) => {
    const { tokenId } = props ?? {};

    return cancelToken(tokenId, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

